MERGE INTO TB_KPI_TARGET AS Target USING (SELECT #{year} AS KPI_YEAR, #{row.waveCd} AS WAVE_CD) AS Source ON (Target.KPI_YEAR = Source.KPI_YEAR AND Target.WAVE_CD = Source.WAVE_CD)
WHEN MATCHED THEN UPDATE SET FAB_IN = TRY_CAST(ISNULL(#{row.fabIn}, '0') AS NUMERIC(18,2)), B1ST = TRY_CAST(ISNULL(#{row.b1st}, '0') AS NUMERIC(18,2)), B2ST = TRY_CAST(ISNULL(#{row.b2st}, '0') AS NUMERIC(18,2)), B3ST = TRY_CAST(ISNULL(#{row.b3st}, '0') AS NUMERIC(18,2)), B4ST = TRY_CAST(ISNULL(#{row.b4st}, '0') AS NUMERIC(18,2)), B5ST = TRY_CAST(ISNULL(#{row.b5st}, '0') AS NUMERIC(18,2)), PG_IN = TRY_CAST(ISNULL(#{row.pgin}, '0') AS NUMERIC(18,2)), A1ST = TRY_CAST(ISNULL(#{row.a1st}, '0') AS NUMERIC(18,2)), A2ST = TRY_CAST(ISNULL(#{row.a2st}, '0') AS NUMERIC(18,2)), A3ST = TRY_CAST(ISNULL(#{row.a3st}, '0') AS NUMERIC(18,2)), A4ST = TRY_CAST(ISNULL(#{row.a4st}, '0') AS NUMERIC(18,2)), A5ST = TRY_CAST(ISNULL(#{row.a5st}, '0') AS NUMERIC(18,2)), FAB_OUT = TRY_CAST(ISNULL(#{row.fabOut}, '0') AS NUMERIC(18,2)), MOD_DT = GETDATE(), MOD_USER = #{userId}
WHEN NOT MATCHED THEN INSERT ( KPI_YEAR, WAVE_CD, FAB_IN, B1ST, B2ST, B3ST, B4ST, B5ST, PG_IN, A1ST, A2ST, A3ST, A4ST, A5ST, FAB_OUT, REG_DT, REG_USER ) VALUES ( Source.KPI_YEAR, Source.WAVE_CD, TRY_CAST(ISNULL(#{row.fabIn}, '0') AS NUMERIC(18,2)), TRY_CAST(ISNULL(#{row.b1st}, '0') AS NUMERIC(18,2)), TRY_CAST(ISNULL(#{row.b2st}, '0') AS NUMERIC(18,2)), TRY_CAST(ISNULL(#{row.b3st}, '0') AS NUMERIC(18,2)), TRY_CAST(ISNULL(#{row.b4st}, '0') AS NUMERIC(18,2)), TRY_CAST(ISNULL(#{row.b5st}, '0') AS NUMERIC(18,2)), TRY_CAST(ISNULL(#{row.pgin}, '0') AS NUMERIC(18,2)), TRY_CAST(ISNULL(#{row.a1st}, '0') AS NUMERIC(18,2)), TRY_CAST(ISNULL(#{row.a2st}, '0') AS NUMERIC(18,2)), TRY_CAST(ISNULL(#{row.a3st}, '0') AS NUMERIC(18,2)), TRY_CAST(ISNULL(#{row.a4st}, '0') AS NUMERIC(18,2)), TRY_CAST(ISNULL(#{row.a5st}, '0') AS NUMERIC(18,2)), TRY_CAST(ISNULL(#{row.fabOut}, '0') AS NUMERIC(18,2)), GETDATE(), #{userId} );

